# fix-cloudinary-upload.ps1
# Root cause: cloudinary.ts configured once at import time with unchecked env vars,
# and upload errors were swallowed into a generic message / local-preview fallback.
# Fix: validate + configure Cloudinary per-call with a clear error, surface the real
# error from the API route, and remove the local-preview fallback in JourneyManager.
$ErrorActionPreference = 'Stop'
Write-Host "Applying Cloudinary upload fix..." -ForegroundColor Cyan

Write-Host "Writing src\lib\cloudinary.ts"
$dir = Split-Path -Parent "src\lib\cloudinary.ts"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64Cloudinary = @"

"@
[System.IO.File]::WriteAllBytes("src\lib\cloudinary.ts", [System.Convert]::FromBase64String($b64Cloudinary))

Write-Host "Writing src\app\api\v1\admin\upload\route.ts"
$dir = Split-Path -Parent "src\app\api\v1\admin\upload\route.ts"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64UploadRoute = @"

"@
[System.IO.File]::WriteAllBytes("src\app\api\v1\admin\upload\route.ts", [System.Convert]::FromBase64String($b64UploadRoute))

Write-Host "Writing src\app\admin\(protected)\journey\JourneyManager.tsx"
$dir = Split-Path -Parent "src\app\admin\(protected)\journey\JourneyManager.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64JourneyManager = @"

"@
[System.IO.File]::WriteAllBytes("src\app\admin\(protected)\journey\JourneyManager.tsx", [System.Convert]::FromBase64String($b64JourneyManager))

Write-Host "Done. 3 files updated." -ForegroundColor Green
Write-Host "Restart your dev server so process.env picks up any .env changes." -ForegroundColor Yellow